import { Capacitor } from "@capacitor/core";
import { LocalNotifications } from "@capacitor/local-notifications";
import { App } from "@capacitor/app";
import { Preferences } from "@capacitor/preferences";
import { StatusBar } from "@capacitor/status-bar";
import { Haptics, ImpactStyle } from "@capacitor/haptics";

export class NativeServices {
  static #isInitialized = false;
  static #swRegistration = null;
  static #isRegistering = false;
  static #platformLogged = false;
  static #swReadyEmitted = false;
  static backButtonHandler = null;

  // Método reutilizable para manejo de errores
  static #handleError(context, error, defaultReturn = false) {
    console.error(`[GS_NOTIF] Error en ${context}:`, error);
    return defaultReturn;
  }

  static async initialize() {
    if (this.#isInitialized) return true;

    try {
      // Log platform info once at startup for web platform
      if (!Capacitor.isNativePlatform() && !this.#platformLogged) {
        console.log("[GS_NOTIF] Platform:", Capacitor.getPlatform());
        console.log(
          "[GS_NOTIF] isNativePlatform:",
          Capacitor.isNativePlatform()
        );
        console.log(
          "[GS_NOTIF] Available plugins:",
          Capacitor.availablePlugins
        );
        this.#platformLogged = true;
      }

      if (Capacitor.isNativePlatform()) {
        await this.#initializeNativePlatform();
      } else {
        // Only initialize SW if needed and not already in progress
        if (!this.#swRegistration && !this.#isRegistering) {
          await this.initializeServiceWorker();
        }
      }

      this.#isInitialized = true;
      return true;
    } catch (error) {
      console.error("Error during initialization:", error);
      return false;
    }
  }

  static async #initializeNativePlatform() {
    // Set up notification listeners first
    if (Capacitor.isPluginAvailable("LocalNotifications")) {
      this.#setupNotificationListeners();
    }

    await Promise.all([this.#setupStatusBar(), this.#setupNotifications()]);

    this.#setupAppListeners();
  }

  static #setupNotificationListeners() {
    LocalNotifications.addListener(
      "localNotificationReceived",
      (notification) => {
        console.log("[GS_NOTIF] Notification received:", notification);
      }
    );

    LocalNotifications.addListener(
      "localNotificationActionPerformed",
      (notification) => {
        console.log("[GS_NOTIF] Notification action performed:", notification);
      }
    );
  }

  static async initializeServiceWorker() {
    if (
      this.#swRegistration ||
      this.#isRegistering ||
      !("serviceWorker" in navigator)
    ) {
      return this.#swRegistration;
    }

    try {
      this.#isRegistering = true;
      console.log("[GS_NOTIF] Registering Service Worker...");

      this.#swRegistration = await navigator.serviceWorker.register("./sw.js", {
        scope: "./",
      });

      if (this.#swRegistration.installing) {
        await new Promise((resolve) => {
          this.#swRegistration.installing.addEventListener(
            "statechange",
            (e) => e.target.state === "activated" && resolve()
          );
        });
      }

      await navigator.serviceWorker.ready;
      console.log("[GS_NOTIF] Service Worker registered and active");

      if (!this.#swReadyEmitted) {
        document.dispatchEvent(new Event("sw-ready"));
        this.#swReadyEmitted = true;
      }

      return this.#swRegistration;
    } catch (error) {
      console.error("[GS_NOTIF] Error registering Service Worker:", error);
      throw error;
    } finally {
      this.#isRegistering = false;
    }
  }

  static async #setupStatusBar() {
    if (!Capacitor.isPluginAvailable("StatusBar")) return;
    try {
      await StatusBar.setBackgroundColor({ color: "#000000" });
    } catch (error) {
      console.warn("Error setting up StatusBar:", error);
    }
  }

  static #setupAppListeners() {
    console.log("[BACK] Configurando manejo del botón Back");

    // Remover el handler anterior si existe
    if (NativeServices.backButtonHandler) {
      NativeServices.backButtonHandler.remove();
      NativeServices.backButtonHandler = null;
    }

    try {
      // Registrar un nuevo listener para el botón Back
      NativeServices.backButtonHandler = App.addListener(
        "backButton",
        async () => {
          console.log("[BACK] Botón Back presionado - Comienza depuración");

          // Verificar estado interno del juego
          console.log("[BACK] Estado de window.game:", !!window.game);
          console.log(
            "[BACK] Estado de window.game.uiService:",
            !!window.game?.uiService
          );

          if (window.game?.uiService) {
            console.log(
              "[BACK] _modalStack:",
              JSON.stringify(window.game.uiService._modalStack || [])
            );
            console.log(
              "[BACK] _activeModals:",
              window.game.uiService._activeModals instanceof Set
                ? [...window.game.uiService._activeModals].join(",")
                : "No es una instancia de Set"
            );
          }

          // Verificar si el modal de victoria está abierto (caso especial 1)
          if (window.game?.uiService) {
            const modalStack = window.game.uiService._modalStack || [];
            const victoryModalOpen = modalStack.some(
              (modalId) =>
                modalId === "victory-modal" ||
                modalId === "modal-victoria" ||
                document
                  .getElementById(modalId)
                  ?.classList.contains("victory-modal")
            );

            if (victoryModalOpen) {
              console.log(
                "[BACK] Modal de victoria detectado, minimizando app..."
              );
              App.minimizeApp();
              return;
            }
          }

          // Caso específico para modal de temas - LLAMAR DIRECTAMENTE AL BOTÓN BACK VISIBLE
          if (window.game?.uiService?._modalStack?.length > 0) {
            const modalStack = window.game.uiService._modalStack;
            const currentModalId = modalStack[modalStack.length - 1];

            // Verificar si estamos en el modal de temas
            if (currentModalId === "theme-modal") {
              console.log(
                "[BACK] Modal de temas detectado, llamando directamente al botón back visible"
              );

              // Obtener el botón back visible y hacer clic en él
              const backButton = document.querySelector(".back-button");
              if (backButton) {
                console.log("[BACK] Botón back encontrado, haciendo clic...");
                backButton.click();
                return;
              } else {
                console.log(
                  "[BACK] No se encontró el botón back, intentando con el API"
                );

                // Si no hay botón, intentar con el método explícito
                if (
                  typeof window.game.uiService.navigateToPreviousModal ===
                  "function"
                ) {
                  try {
                    window.game.uiService.navigateToPreviousModal();
                    console.log(
                      "[BACK] Navegación ejecutada con navigateToPreviousModal()"
                    );
                    return;
                  } catch (e) {
                    console.error(
                      "[BACK] Error al ejecutar navigateToPreviousModal():",
                      e
                    );
                  }
                }
              }
            }
          }

          // Si llegamos aquí, o no estamos en el modal de temas o no se pudo manejar ese caso específico
          // Continuar con el método general

          // Depurar elementos DOM
          console.log(
            "[BACK] Modales en el DOM:",
            document.querySelectorAll(".modal-overlay").length
          );
          console.log(
            "[BACK] Modales activos en el DOM:",
            document.querySelectorAll(".modal-overlay.active").length
          );

          // Intentar la estrategia de la tecla Escape primero
          try {
            console.log("[BACK] Intentando emitir tecla Escape...");
            const escapeEvent = new KeyboardEvent("keydown", {
              key: "Escape",
              code: "Escape",
              keyCode: 27,
              which: 27,
              bubbles: true,
              cancelable: true,
            });

            document.activeElement.dispatchEvent(escapeEvent);
            document.body.dispatchEvent(escapeEvent);
            window.dispatchEvent(escapeEvent);

            // Esperar un momento para ver si el modal se cierra
            await new Promise((resolve) => setTimeout(resolve, 100));

            // Verificar si sigue habiendo modales activos
            const modalesAunActivos = document.querySelectorAll(
              ".modal-overlay.active"
            ).length;
            console.log(
              "[BACK] Modales activos después de Escape:",
              modalesAunActivos
            );

            if (modalesAunActivos === 0) {
              console.log("[BACK] Modal cerrado exitosamente con tecla Escape");
              return;
            }
          } catch (escapeError) {
            console.error("[BACK] Error al emitir evento Escape:", escapeError);
          }

          // Continuar con los otros métodos si Escape no funcionó
          let modalClosed = false;

          // Método 1: Usar directamente la función UI del juego
          if (window.game?.uiService?._modalStack?.length > 0) {
            const modalStack = window.game.uiService._modalStack;
            const lastModalId = modalStack[modalStack.length - 1];
            console.log(
              `[BACK] Intentando cerrar modal ${lastModalId} directamente...`
            );

            // Caso general: Si hay múltiples modales, usar navigateToPreviousModal
            if (
              modalStack.length > 1 &&
              typeof window.game.uiService.navigateToPreviousModal ===
                "function"
            ) {
              console.log(
                "[BACK] Múltiples modales detectados, usando navigateToPreviousModal"
              );
              window.game.uiService.navigateToPreviousModal();
              modalClosed = true;
            } else {
              // Solo hay un modal, intentar cerrarlo con el método estándar hideModal
              try {
                if (typeof window.game.uiService.hideModal === "function") {
                  window.game.uiService.hideModal(lastModalId);
                  console.log(
                    `[BACK] Modal ${lastModalId} cerrado con hideModal()`
                  );
                  modalClosed = true;
                }
              } catch (e) {
                console.error(
                  `[BACK] Error en hideModal('${lastModalId}'):`,
                  e
                );

                // Como último recurso, usar hideModalInstantly
                if (
                  !modalClosed &&
                  typeof window.game.uiService.hideModalInstantly === "function"
                ) {
                  try {
                    window.game.uiService.hideModalInstantly(lastModalId);
                    console.log(
                      `[BACK] Modal ${lastModalId} cerrado con hideModalInstantly() como respaldo`
                    );
                    modalClosed = true;
                  } catch (e2) {
                    console.error(
                      `[BACK] Error también con hideModalInstantly:`,
                      e2
                    );
                  }
                }
              }
            }
          }

          // Método 2: Buscar en el DOM e intentar diferentes estrategias
          if (!modalClosed) {
            const modalElements = Array.from(
              document.querySelectorAll(".modal-overlay")
            ).filter(
              (m) => m.classList.contains("active") || !m.hasAttribute("hidden")
            );

            console.log(
              `[BACK] Encontrados ${modalElements.length} modales activos en el DOM`
            );

            if (modalElements.length > 0) {
              // Comprobar primero si alguno de los modales activos es el modal de victoria
              const victoryModal = modalElements.find(
                (modal) =>
                  modal.classList.contains("victory-modal") ||
                  modal.id === "victory-modal" ||
                  modal.id === "modal-victoria"
              );

              if (victoryModal) {
                console.log(
                  "[BACK] Modal de victoria detectado en DOM, minimizando app..."
                );
                App.minimizeApp();
                return;
              }

              // Caso específico para modal de temas
              if (modalElements.length > 0) {
                const lastModal = modalElements[modalElements.length - 1];
                const modalId = lastModal.id || "modal_sin_id";

                if (modalId === "theme-modal" || modalId.includes("theme")) {
                  console.log(
                    "[BACK] Modal de temas detectado en DOM, buscando botón volver..."
                  );

                  // Usar document.querySelector para obtener el botón back desde cualquier parte del DOM
                  const backButton = document.querySelector(".back-button");

                  if (backButton) {
                    console.log(
                      "[BACK] Botón volver encontrado en modal de temas, haciendo clic..."
                    );
                    backButton.click();
                    modalClosed = true;
                    return; // Importante: retornar inmediatamente después del clic
                  }
                }
              }

              // Si hay múltiples modales pero no es el caso específico de temas o no se encontró el botón back
              if (!modalClosed && modalElements.length > 1) {
                const lastModal = modalElements[modalElements.length - 1];
                const modalId = lastModal.id || "modal_sin_id";
                console.log(
                  `[BACK] Múltiples modales en DOM. Intentando cerrar último modal: ${modalId}...`
                );

                // Buscar botones específicos de 'volver' primero
                const backButtons = lastModal.querySelectorAll(
                  '.back-button, [data-action="back"], .btn-back, button.back'
                );

                if (backButtons.length > 0) {
                  console.log(
                    `[BACK] Botón volver encontrado en modal ${modalId}, haciendo clic...`
                  );
                  backButtons[0].click();
                  modalClosed = true;
                } else {
                  // Si no hay botón específico de volver, buscar cualquier botón de cierre
                  const closeButtons = lastModal.querySelectorAll(
                    '.close-button, [data-action="close"]'
                  );
                  if (closeButtons.length > 0) {
                    console.log(
                      `[BACK] Botón cerrar encontrado en modal ${modalId}, haciendo clic...`
                    );
                    closeButtons[0].click();
                    modalClosed = true;
                  } else {
                    // Como último recurso, simular clic en el fondo del modal
                    console.log(
                      `[BACK] Simulando clic en el fondo del modal...`
                    );
                    const clickEvent = new MouseEvent("click", {
                      bubbles: true,
                      cancelable: true,
                      view: window,
                    });
                    lastModal.dispatchEvent(clickEvent);
                    modalClosed = true;
                  }
                }
              } else if (!modalClosed) {
                // Solo hay un modal, cerrarlo normalmente
                const lastModal = modalElements[0];
                const modalId = lastModal.id || "modal_sin_id";
                console.log(
                  `[BACK] Un solo modal en DOM: ${modalId}, cerrando...`
                );

                const buttonSelectors = [
                  ".close-button",
                  ".back-button",
                  '[data-action="close"]',
                  ".modal-close",
                  "button.close",
                  "button.btn-close",
                  ".modal-header .close",
                  ".modal-footer .btn",
                ];

                // Unir todos los selectores en uno
                const allButtons = lastModal.querySelectorAll(
                  buttonSelectors.join(",")
                );

                if (allButtons.length > 0) {
                  console.log(
                    `[BACK] Encontrado botón de cierre en modal. Haciendo clic...`
                  );
                  allButtons[0].click();
                  modalClosed = true;
                } else {
                  // Alternativa: Simular clic en el fondo del modal
                  console.log(
                    `[BACK] No se encontraron botones. Simulando clic en fondo del modal...`
                  );
                  const clickEvent = new MouseEvent("click", {
                    bubbles: true,
                    cancelable: true,
                    view: window,
                  });
                  lastModal.dispatchEvent(clickEvent);
                  modalClosed = true;
                }
              }
            }
          }

          // Si no se encontraron o no se pudieron cerrar modales, minimizar la app
          if (!modalClosed) {
            console.log(
              "[BACK] No hay modales o no se pudieron cerrar. Minimizando app..."
            );
            App.minimizeApp();
          } else {
            console.log("[BACK] Modal cerrado exitosamente");
          }
        }
      );

      console.log("[BACK] Manejo del botón Back configurado correctamente");
    } catch (error) {
      console.error(
        "[BACK] Error al configurar el manejo del botón Back:",
        error
      );
    }

    // Manejar cambios de estado de la app
    App.addListener("appStateChange", ({ isActive }) => {
      console.log(
        `[APP] Estado de la app cambiado: ${isActive ? "activo" : "inactivo"}`
      );
      document.dispatchEvent(new Event(isActive ? "appResume" : "appPause"));
    });
  }

  static async #setupNotifications() {
    console.log("[GS_NOTIF] Starting notification setup");

    try {
      if (Capacitor.isNativePlatform()) {
        if (!Capacitor.isPluginAvailable("LocalNotifications")) {
          console.warn("[GS_NOTIF] LocalNotifications plugin not available");
          return false;
        }

        // Configurar canal para Android
        if (Capacitor.getPlatform() === "android") {
          console.log("[GS_NOTIF] Setting up Android channel");
          await LocalNotifications.createChannel({
            id: "default",
            name: "Game Notifications",
            description: "Game progress and achievements",
            importance: 5,
            visibility: 1,
            vibration: true,
            lights: true,
            sound: null,
            lightColor: "#488AFF",
          }).catch((err) =>
            console.warn("[GS_NOTIF] Error creating channel:", err)
          );
        }

        // Verificar y solicitar permisos
        const perms = await LocalNotifications.checkPermissions();
        console.log("[GS_NOTIF] Current permissions:", perms);

        if (perms.display !== "granted") {
          const newPerms = await LocalNotifications.requestPermissions();
          console.log("[GS_NOTIF] New permissions:", newPerms);
          return newPerms.display === "granted";
        }

        return true;
      } else {
        // Web Notifications
        if (!("Notification" in window)) {
          console.warn("[GS_NOTIF] Este navegador no soporta notificaciones");
          return false;
        }

        if (Notification.permission === "granted") {
          return true;
        }

        if (Notification.permission !== "denied") {
          const permission = await Notification.requestPermission();
          return permission === "granted";
        }

        return false;
      }
    } catch (error) {
      console.error("[GS_NOTIF] Error setting up notifications:", error);
      return false;
    }
  }

  static async vibrate(pattern = "LIGHT") {
    try {
      if (Capacitor.isNativePlatform()) {
        // Usar Haptics API en plataformas nativas
        const impacts = {
          LIGHT: ImpactStyle.Light,
          MEDIUM: ImpactStyle.Medium,
          HEAVY: ImpactStyle.Heavy,
        };
        return await Haptics.impact({
          style: impacts[pattern] || impacts.LIGHT,
        });
      } else {
        // Usar navigator.vibrate en web
        if (!navigator.vibrate) return false;
        const patterns = {
          LIGHT: [100],
          MEDIUM: [200, 100, 200],
          HEAVY: [300, 100, 300],
        };
        return navigator.vibrate(patterns[pattern] || patterns.LIGHT);
      }
    } catch (error) {
      return this.#handleError("vibrate", error);
    }
  }

  static async sendNotification(title, body, options = {}) {
    try {
      await this.initialize();

      if (Capacitor.isNativePlatform()) {
        // Usar solo LocalNotifications para plataformas nativas
        if (!Capacitor.isPluginAvailable("LocalNotifications")) {
          throw new Error("LocalNotifications no está disponible");
        }

        const notificationId = Math.floor(Math.random() * 2147483647);
        await LocalNotifications.schedule({
          notifications: [
            {
              title,
              body,
              id: notificationId,
              channelId: "default",
              ...options,
              sound: options.sound || null,
              iconColor: options.iconColor || "#488AFF",
              smallIcon: options.smallIcon || "ic_stat_notification",
            },
          ],
        });
      } else {
        // Usar solo Web Notifications para web
        if (!("Notification" in window)) {
          throw new Error("Web Notifications no está disponible");
        }

        const registration = await navigator.serviceWorker?.ready;
        if (!registration) {
          throw new Error("Service Worker no está registrado");
        }

        await registration.showNotification(title, {
          body,
          icon: "/assets/icon_tr.png",
          badge: "/assets/icon.png",
          vibrate: [200, 100, 200],
          ...options,
        });
      }

      return true;
    } catch (error) {
      return this.#handleError("sendNotification", error);
    }
  }

  static async get(key, defaultValue = null) {
    try {
      const { value } = await Preferences.get({ key });
      return value ? JSON.parse(value) : defaultValue;
    } catch (error) {
      return this.#handleError(`get(${key})`, error, defaultValue);
    }
  }

  static async setData(key, value) {
    try {
      await Preferences.set({ key, value: JSON.stringify(value) });
      return true;
    } catch (error) {
      return this.#handleError(`setData(${key})`, error);
    }
  }

  static getAssetPath(path) {
    // Limpia la ruta eliminando ./ o / iniciales y referencias a assets/
    const cleanPath = path.replace(/^\.?\/?/, "").replace(/^assets\//, "");

    if (Capacitor.isNativePlatform()) {
      return `file:///android_asset/public/${cleanPath}`;
    } else {
      // Determinar si estamos en GitHub Pages y obtener la ruta base
      const isGitHubPages = window.location.hostname.includes("github.io");
      let basePath = "";

      if (isGitHubPages) {
        // En GitHub Pages, extraer el nombre del repositorio de la URL
        const pathSegments = window.location.pathname.split("/");
        // Asumimos que el primer segmento después del / inicial es el nombre del repositorio
        if (pathSegments.length > 1) {
          basePath = `/${pathSegments[1]}/`;
        }
      } else {
        // En desarrollo local o otros entornos
        basePath = "./";
      }

      return `${basePath}${cleanPath}`;
    }
  }
}
