import { NativeServices } from "./platform.js";

class StorageManager {
  static STORAGE_KEYS = {
    CURRENT_LEVEL: "currentLevel",
    CURRENT_THEME: "currentTheme",
    VIBRATION_ENABLED: "vibrationEnabled",
    GAME_CONFIG: "gameConfig",
  };

  static isVibrationEnabled = true;
  static isInitialized = false;

  static async initialize() {
    if (this.isInitialized) return;

    try {
      // Cargar estado de vibración usando las claves predefinidas
      const vibrationEnabled = await NativeServices.get(
        this.STORAGE_KEYS.VIBRATION_ENABLED
      );
      this.isVibrationEnabled = vibrationEnabled ?? true;

      this.isInitialized = true;
      console.log("✅ StorageManager inicializado correctamente");
    } catch (error) {
      console.error("Error initializing StorageManager:", error);
      this.isInitialized = true; // Marcamos como inicializado con valores por defecto
    }
  }

  static async get(key) {
    try {
      return await NativeServices.get(key);
    } catch (error) {
      console.error(`Error getting value for key ${key}:`, error);
      return null;
    }
  }

  static async setData(key, value) {
    try {
      return await NativeServices.setData(key, value);
    } catch (error) {
      console.error(`Error setting value for key ${key}:`, error);
      return false;
    }
  }

  static async getCurrentLevel() {
    return await this.get(this.STORAGE_KEYS.CURRENT_LEVEL);
  }

  static async setCurrentLevel(levelId) {
    return await this.setData(this.STORAGE_KEYS.CURRENT_LEVEL, levelId);
  }

  static async getCurrentTheme() {
    return (await this.get(this.STORAGE_KEYS.CURRENT_THEME)) || "dark";
  }

  static async setCurrentTheme(theme) {
    return await this.setData(this.STORAGE_KEYS.CURRENT_THEME, theme);
  }

  static async setVibrationEnabled(enabled) {
    this.isVibrationEnabled = enabled;
    return await this.setData(this.STORAGE_KEYS.VIBRATION_ENABLED, enabled);
  }
}

export { StorageManager };
